(function () {
  "use strict";

  var ctx = window.ORG_CTX || { role: "viewer", user_id: null };
  var canManage = ["org_admin", "region_manager", "branch_manager", "coach"].indexOf(ctx.role) >= 0;

  var $rows = document.querySelector("[data-players-rows]");
  var $regionFilter = document.getElementById("player-region-filter");
  var $branchFilter = document.getElementById("player-branch-filter");
  var $teamFilter = document.getElementById("player-team-filter");
  var $modal = document.getElementById("player-modal");
  var $form = document.getElementById("player-form");
  var $error = $modal.querySelector("[data-error]");
  var $teamSelect = document.getElementById("player-team");

  var $modalRegion = document.getElementById("player-modal-region");
  var $modalBranch = document.getElementById("player-modal-branch");
  var $confirmModal = document.getElementById("confirm-modal");
  var $confirmName = $confirmModal.querySelector("[data-confirm-name]");
  var $confirmError = $confirmModal.querySelector("[data-confirm-error]");

  var regionsById = {};
  var branchesById = {};
  var teamsById = {};
  var pendingDeleteId = null;

  var SVG_NS = "http://www.w3.org/2000/svg";
  function parseSvg(s) { return new DOMParser().parseFromString(s, "image/svg+xml").documentElement; }
  var SVG_EDIT_TPL = parseSvg(
    '<svg xmlns="' + SVG_NS + '" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">' +
    '<path d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13l-2.685.8.8-2.685a4.5 4.5 0 011.13-1.897L16.863 4.487zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10"/>' +
    "</svg>"
  );
  var SVG_TRASH_TPL = parseSvg(
    '<svg xmlns="' + SVG_NS + '" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">' +
    '<path d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0"/>' +
    "</svg>"
  );

  function openModal(m) { m.classList.add("is-open"); m.setAttribute("aria-hidden", "false"); }
  function closeModal(m) { m.classList.remove("is-open"); m.setAttribute("aria-hidden", "true"); }
  function showError(el, t) { el.textContent = t; el.classList.remove("org-hidden"); }
  function hideError(el) { el.textContent = ""; el.classList.add("org-hidden"); }

  async function api(method, url, body) {
    var init = { method: method, headers: { "Accept": "application/json" } };
    if (body !== undefined) {
      init.headers["Content-Type"] = "application/json";
      init.body = JSON.stringify(body);
    }
    var r = await fetch(url, init);
    if (r.status === 204) return null;
    var data = null;
    try { data = await r.json(); } catch (_e) {}
    if (!r.ok) {
      var msg = (data && (data.detail || data.message)) || ("שגיאה " + r.status);
      throw { status: r.status, code: (data && data.code) || null, message: msg };
    }
    return data;
  }

  function el(tag, opts, children) {
    var n = document.createElement(tag);
    if (opts) {
      if (opts.className) n.className = opts.className;
      if (opts.text != null) n.textContent = opts.text;
      if (opts.attrs) Object.keys(opts.attrs).forEach(function (k) { n.setAttribute(k, opts.attrs[k]); });
    }
    if (children) children.forEach(function (c) { n.appendChild(c); });
    return n;
  }

  function iconBtn(svgTpl, attrs, isDanger) {
    var b = document.createElement("button");
    b.className = "org-btn-icon" + (isDanger ? " is-danger" : "");
    Object.keys(attrs).forEach(function (k) { b.setAttribute(k, attrs[k]); });
    b.appendChild(svgTpl.cloneNode(true));
    return b;
  }

  function fillSelect(sel, items, valueKey, labelKey, includeBlank, blankLabel) {
    while (sel.options.length > 0) sel.remove(0);
    if (includeBlank) {
      var blank = document.createElement("option");
      blank.value = "";
      blank.textContent = blankLabel || "— ללא —";
      sel.appendChild(blank);
    }
    items.forEach(function (it) {
      var o = document.createElement("option");
      o.value = String(it[valueKey]);
      o.textContent = it[labelKey];
      sel.appendChild(o);
    });
  }

  async function loadReferenceData() {
    try {
      var [regions, branches, teams] = await Promise.all([
        api("GET", "/org/api/regions").catch(function () { return { regions: [] }; }),
        api("GET", "/org/api/branches").catch(function () { return { branches: [] }; }),
        api("GET", "/org/api/teams").catch(function () { return { teams: [] }; }),
      ]);
      regionsById = {};
      (regions.regions || []).forEach(function (r) { regionsById[r.id] = r; });
      branchesById = {};
      (branches.branches || []).forEach(function (b) { branchesById[b.id] = b; });
      teamsById = {};
      (teams.teams || []).forEach(function (t) { teamsById[t.id] = t; });

      var regionList = Object.values(regionsById).sort(function (a, b) {
        return a.name.localeCompare(b.name);
      });
      fillSelect($regionFilter, regionList, "id", "name", true, "כל המחוזות");

      refreshBranchFilter();
      refreshTeamFilter();

      if ($modalRegion) {
        fillSelect($modalRegion, regionList, "id", "name", true, "— ללא מחוז —");
      }

      refreshModalBranchOptions("");
      refreshModalTeamOptions("", "");
    } catch (_e) {
      regionsById = {}; branchesById = {}; teamsById = {};
    }
  }

  function refreshModalBranchOptions(regionId) {
    if (!$modalBranch) return;
    var prev = $modalBranch.value;
    var list = Object.values(branchesById)
      .filter(function (b) { return !regionId || String(b.region_id) === String(regionId); })
      .sort(function (a, b) { return a.name.localeCompare(b.name); });
    fillSelect($modalBranch, list, "id", "name", true, "— ללא סניף —");
    var stillValid = list.some(function (b) { return String(b.id) === prev; });
    $modalBranch.value = stillValid ? prev : "";
  }

  function refreshModalTeamOptions(regionId, branchId) {
    if (!$teamSelect) return;
    var prev = $teamSelect.value;
    var list = Object.values(teamsById).filter(function (t) {
      if (branchId) return String(t.branch_id) === String(branchId);
      if (regionId) {
        var b = t.branch_id != null ? branchesById[t.branch_id] : null;
        return b && String(b.region_id) === String(regionId);
      }
      return true;
    }).sort(function (a, b) { return a.team_name.localeCompare(b.team_name); });
    fillSelect($teamSelect, list, "id", "team_name", true, "— בחר קבוצה —");
    var stillValid = list.some(function (t) { return String(t.id) === prev; });
    $teamSelect.value = stillValid ? prev : "";
  }

  function refreshBranchFilter() {
    var rid = $regionFilter.value;
    var list = Object.values(branchesById)
      .filter(function (b) { return !rid || String(b.region_id) === String(rid); })
      .sort(function (a, b) { return a.name.localeCompare(b.name); });
    var prev = $branchFilter.value;
    fillSelect($branchFilter, list, "id", "name", true, "כל הסניפים");
    var stillValid = list.some(function (b) { return String(b.id) === prev; });
    $branchFilter.value = stillValid ? prev : "";
  }

  function refreshTeamFilter() {
    var rid = $regionFilter.value;
    var bid = $branchFilter.value;
    var list = Object.values(teamsById).filter(function (t) {
      if (bid) return String(t.branch_id) === String(bid);
      if (rid) {
        var b = t.branch_id != null ? branchesById[t.branch_id] : null;
        return b && String(b.region_id) === String(rid);
      }
      return true;
    }).sort(function (a, b) { return a.team_name.localeCompare(b.team_name); });
    var prev = $teamFilter.value;
    fillSelect($teamFilter, list, "id", "team_name", true, "כל הקבוצות");
    var stillValid = list.some(function (t) { return String(t.id) === prev; });
    $teamFilter.value = stillValid ? prev : "";
  }

  async function loadPlayers() {
    var url = "/org/api/players";
    var params = [];
    var tid = $teamFilter.value;
    var bid = $branchFilter.value;
    var rid = $regionFilter.value;

    if (tid) params.push("team_id=" + encodeURIComponent(tid));
    else if (bid) params.push("branch_id=" + encodeURIComponent(bid));
    else if (rid) params.push("region_id=" + encodeURIComponent(rid));
    if (params.length) url += "?" + params.join("&");
    try {
      var data = await api("GET", url);
      renderRows(data.players || []);
    } catch (e) {
      setEmpty(e.message);
    }
  }

  function setEmpty(msg) {
    $rows.replaceChildren(
      el("tr", null, [el("td", { className: "org-table-empty", text: msg, attrs: { colspan: "7" } })])
    );
  }

  function renderRows(players) {
    if (!players.length) {
      setEmpty(canManage ? 'אין שחקנים. לחץ "שחקן חדש" כדי להוסיף.' : "אין שחקנים.");
      return;
    }
    $rows.replaceChildren.apply(
      $rows,
      players.map(function (p) {
        var initial = (p.name || "?").slice(0, 1).toUpperCase();
        var nameLink = el("a", {
          attrs: { href: "/org/players/" + p.id, style: "color: inherit; text-decoration: none;" },
        }, [
          el("div", { className: "org-flex org-items-center org-gap-3" }, [
            el("span", { className: "org-avatar", text: initial }),
            el("strong", { text: p.name }),
          ]),
        ]);

        var nameCell = el("td", null, [nameLink]);
        var numberCell = el("td", { text: p.number != null ? String(p.number) : "—" });
        var positionCell = el("td", null, [
          el("span", {
            className: p.position ? "org-pill" : "org-pill org-pill--muted",
            text: p.position || "—",
          }),
        ]);
        var ageCell = el("td", { text: p.age != null ? String(p.age) : "—" });
        var teamName = teamsById[p.team_id] ? teamsById[p.team_id].team_name : "—";
        var teamCell = el("td", null, [
          el("span", { className: "org-pill", text: teamName }),
        ]);

        var pendingCount = p.pending_approvals || 0;
        var approvalsCell = el("td", null);
        if (pendingCount > 0) {
          var btn = document.createElement("button");
          btn.type = "button";
          btn.className = "org-pill org-pill--warn";
          btn.style.cursor = "pointer";
          btn.style.border = "0";
          btn.textContent = String(pendingCount) + " ממתינים";
          btn.setAttribute("data-approvals-player", String(p.id));
          btn.setAttribute("data-name", p.name);
          approvalsCell.appendChild(btn);
        } else {
          var okBtn = document.createElement("button");
          okBtn.type = "button";
          okBtn.className = "org-pill org-pill--ok";
          okBtn.style.cursor = "pointer";
          okBtn.style.border = "0";
          okBtn.textContent = "✓";
          okBtn.setAttribute("data-approvals-player", String(p.id));
          okBtn.setAttribute("data-name", p.name);
          approvalsCell.appendChild(okBtn);
        }

        var actions = [];
        if (canManage) {
          actions.push(iconBtn(SVG_EDIT_TPL, {
            type: "button",
            "data-edit-player": String(p.id),
            title: "עריכה",
            "aria-label": "עריכה",
          }, false));
          actions.push(iconBtn(SVG_TRASH_TPL, {
            type: "button",
            "data-delete-player": String(p.id),
            "data-name": p.name,
            title: "הסרה",
            "aria-label": "הסרה",
          }, true));
        }
        var actionsCell = el("td", { className: "org-table-actions" }, actions);
        return el("tr", null, [nameCell, numberCell, positionCell, ageCell, teamCell, approvalsCell, actionsCell]);
      })
    );
  }

  var $approvalsModal = document.getElementById("approvals-modal");
  var $approvalsRows = $approvalsModal && $approvalsModal.querySelector("[data-approvals-rows]");
  var $approvalsTitle = $approvalsModal && $approvalsModal.querySelector("[data-approvals-title]");

  var APPROVAL_STATUS_LABEL = {
    NOT_OPENED: "לא נפתח",
    OPENED: "נפתח",
    FILLED: "מולא",
    SIGNED: "נחתם",
    EXPIRED: "פג תוקף",
    DECLINED: "נדחה",
  };
  var APPROVAL_STATUS_KIND = {
    SIGNED: "org-pill--ok",
    NOT_OPENED: "org-pill--muted",
    EXPIRED: "org-pill--err",
    DECLINED: "org-pill--err",
    OPENED: "org-pill--warn",
    FILLED: "org-pill--warn",
  };

  function fmtDate(iso) {
    if (!iso) return "—";
    try {
      var d = new Date(iso);
      return d.toLocaleDateString("he-IL") + " " + d.toLocaleTimeString("he-IL", { hour: "2-digit", minute: "2-digit" });
    } catch (_e) { return iso; }
  }

  async function openApprovals(playerId, playerName) {
    if (!$approvalsModal) return;
    $approvalsTitle.textContent = "אישורי הורים — " + playerName;
    $approvalsRows.replaceChildren(
      el("tr", null, [el("td", { className: "org-table-empty", text: "טוען…", attrs: { colspan: "5" } })])
    );
    openModal($approvalsModal);
    try {
      var data = await api("GET", "/org/api/players/" + playerId + "/deliveries");
      var rows = data.deliveries || [];
      if (!rows.length) {
        $approvalsRows.replaceChildren(
          el("tr", null, [el("td", { className: "org-table-empty", text: "אין אישורי הורים לשחקן זה.", attrs: { colspan: "5" } })])
        );
        return;
      }
      $approvalsRows.replaceChildren.apply(
        $approvalsRows,
        rows.map(function (r) {
          var doc = el("td", { text: r.recipient_name ? "להורה: " + r.recipient_name : "—" });
          var status = el("td", null, [
            el("span", {
              className: "org-pill " + (APPROVAL_STATUS_KIND[r.document_status] || ""),
              text: APPROVAL_STATUS_LABEL[r.document_status] || r.document_status,
            }),
          ]);
          var ch = el("td", { className: "org-text-sm", text: r.channel_used || "—" });
          var sent = el("td", { className: "org-text-sm org-text-muted", text: fmtDate(r.sent_at) });
          var signed = el("td", { className: "org-text-sm", text: fmtDate(r.signed_at) });
          return el("tr", null, [doc, status, ch, sent, signed]);
        })
      );
    } catch (e) {
      $approvalsRows.replaceChildren(
        el("tr", null, [el("td", { className: "org-table-empty", text: e.message, attrs: { colspan: "5" } })])
      );
    }
  }

  document.addEventListener("click", function (ev) {
    var t = ev.target.closest("[data-approvals-player]");
    if (t) {
      ev.preventDefault();
      openApprovals(parseInt(t.getAttribute("data-approvals-player"), 10), t.getAttribute("data-name") || "");
    }
    if ($approvalsModal && ev.target.closest("[data-action='close-approvals']")) {
      closeModal($approvalsModal);
    }
  });

  function openNew() {
    $form.reset();
    $form.elements.id.value = "";

    if ($modalRegion) $modalRegion.value = "";
    refreshModalBranchOptions("");
    refreshModalTeamOptions("", "");
    document.getElementById("player-modal-title").textContent = "שחקן חדש";
    hideError($error);
    openModal($modal);
    setTimeout(function () { $form.elements.name.focus(); }, 50);
  }

  async function openEdit(id) {
    try {
      var p = await api("GET", "/org/api/players/" + id);
      $form.elements.id.value = String(p.id);
      $form.elements.name.value = p.name || "";

      var derivedBranch = "";
      var derivedRegion = "";
      if (p.team_id != null && teamsById[p.team_id]) {
        var team = teamsById[p.team_id];
        if (team.branch_id != null) {
          derivedBranch = String(team.branch_id);
          var branch = branchesById[team.branch_id];
          if (branch && branch.region_id != null) {
            derivedRegion = String(branch.region_id);
          }
        }
      }
      if ($modalRegion) $modalRegion.value = derivedRegion;
      refreshModalBranchOptions(derivedRegion);
      if ($modalBranch) $modalBranch.value = derivedBranch;
      refreshModalTeamOptions(derivedRegion, derivedBranch);
      $form.elements.team_id.value = p.team_id != null ? String(p.team_id) : "";
      $form.elements.number.value = p.number != null ? String(p.number) : "";
      $form.elements.age.value = p.age != null ? String(p.age) : "";
      $form.elements.position.value = p.position || "";
      document.getElementById("player-modal-title").textContent = "עריכת שחקן";
      hideError($error);
      openModal($modal);
    } catch (e) {
      window.OrgToast && window.OrgToast.show(e.message, "danger");
    }
  }

  if ($modalRegion) {
    $modalRegion.addEventListener("change", function () {
      refreshModalBranchOptions($modalRegion.value);
      refreshModalTeamOptions($modalRegion.value, "");
    });
  }
  if ($modalBranch) {
    $modalBranch.addEventListener("change", function () {
      refreshModalTeamOptions($modalRegion ? $modalRegion.value : "", $modalBranch.value);
    });
  }

  $form.addEventListener("submit", async function (ev) {
    ev.preventDefault();
    hideError($error);
    var id = $form.elements.id.value;
    var f = $form.elements;
    var payload = {
      name: f.name.value.trim(),
      team_id: f.team_id.value ? parseInt(f.team_id.value, 10) : null,
      number: f.number.value ? parseInt(f.number.value, 10) : null,
      age: f.age.value ? parseInt(f.age.value, 10) : null,
      position: f.position.value || null,
    };
    if (!id && payload.team_id === null) {
      showError($error, "בחר קבוצה.");
      return;
    }
    try {
      if (id) {

        var patchPayload = Object.assign({}, payload);
        delete patchPayload.team_id;
        await api("PATCH", "/org/api/players/" + id, patchPayload);
        window.OrgToast && window.OrgToast.show("השחקן עודכן", "success");
      } else {
        await api("POST", "/org/api/players", payload);
        window.OrgToast && window.OrgToast.show("השחקן נוצר", "success");
      }
      closeModal($modal);
      loadPlayers();
    } catch (e) {
      showError($error, e.message);
    }
  });

  function openDelete(id, name) {
    pendingDeleteId = id;
    $confirmName.textContent = name;
    hideError($confirmError);
    openModal($confirmModal);
  }

  async function confirmDelete() {
    if (!pendingDeleteId) return;
    try {
      await api("DELETE", "/org/api/players/" + pendingDeleteId);
      closeModal($confirmModal);
      window.OrgToast && window.OrgToast.show("השחקן הוסר מהסגל", "success");
      pendingDeleteId = null;
      loadPlayers();
    } catch (e) {
      showError($confirmError, e.message);
    }
  }

  document.addEventListener("click", function (e) {
    var t = e.target.closest("[data-action], [data-edit-player], [data-delete-player]");
    if (!t) return;
    if (t.dataset.action === "open-new-player") return openNew();
    if (t.dataset.action === "close-player") return closeModal($modal);
    if (t.dataset.action === "close-confirm") return closeModal($confirmModal);
    if (t.dataset.action === "do-confirm") return confirmDelete();
    if (t.dataset.editPlayer) return openEdit(t.dataset.editPlayer);
    if (t.dataset.deletePlayer) return openDelete(t.dataset.deletePlayer, t.dataset.name);
  });

  document.addEventListener("keydown", function (e) {
    if (e.key !== "Escape") return;
    closeModal($modal);
    closeModal($confirmModal);
  });

  [$modal, $confirmModal].forEach(function (m) {
    m.addEventListener("click", function (e) { if (e.target === m) closeModal(m); });
  });

  $regionFilter.addEventListener("change", function () {
    refreshBranchFilter();
    refreshTeamFilter();
    loadPlayers();
  });
  $branchFilter.addEventListener("change", function () {
    refreshTeamFilter();
    loadPlayers();
  });
  $teamFilter.addEventListener("change", loadPlayers);

  async function boot() {
    await loadReferenceData();
    await loadPlayers();
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", boot);
  } else {
    boot();
  }
})();